using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class StoreCategoryConfiguration : IEntityTypeConfiguration<StoreCategory>{public void Configure(EntityTypeBuilder<StoreCategory> builder){builder.ToTable("store_categories");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("category_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Code).HasMaxLength(50).IsRequired();builder.Property(e => e.Name).HasMaxLength(100).IsRequired();builder.Property(e => e.ShortDescription).HasMaxLength(200);builder.Property(e => e.IconCode).HasMaxLength(30);builder.Property(e => e.TypicalPriceFactor).HasColumnType("decimal(4,2)").HasDefaultValue(1.0m);builder.HasIndex(e => e.Code).IsUnique();}}
